class BasicForm{initClipboardBasic(){const n=document.getElementById("clipboard_example"),e=n.nextElementSibling;new ClipboardJS(e,{target:n,text:function(){return n.value}}).on("success",function(n){const i=e.innerHTML;"Copied!"!==e.innerHTML&&(e.innerHTML="Copied!",setTimeout(function(){e.innerHTML=i},3e3))})}initClipboardCut(){const n=document.getElementById("clipboard_cut"),e=n.nextElementSibling;new ClipboardJS(e,{target:n,text:function(){return n.innerText}}).on("success",function(n){const i=e.innerHTML;"Copied!"!==e.innerHTML&&(e.innerHTML="Copied!",setTimeout(function(){e.innerHTML=i},3e3))})}initClipboardText(){const n=document.getElementById("clipboard_text");new ClipboardJS(n).on("success",function(e){const i=n.innerHTML;"Copied!"!==n.innerHTML&&(n.innerHTML="Copied!",setTimeout(function(){n.innerHTML=i},3e3))})}init(){this.initClipboardBasic(),this.initClipboardCut(),this.initClipboardText()}}document.addEventListener("DOMContentLoaded",function(n){(new BasicForm).init()});